SELECT ?player (COUNT(?match) AS ?count) WHERE {
  ?match wdt:P178 wd:Q5027;
         wdt:P1064 ?home;
         wdt:P1065 ?away.
  FILTER ( ( ( ?home = wd:Q5442 && ?away = wd:Q7021 ) || ( ?home = wd:Q7021 && ?away = wd:Q5442 ) ) )
  { ?player wdt:P195 ?home } UNION { ?player wdt:P195 ?away }
} GROUP BY ?player ORDER BY DESC(?count) LIMIT 1

